    private SOAPMessage createSOAPFaultResponse(String faultMessage) {
        try {
            MessageFactory factory = MessageFactory.newInstance(SOAPConstants.SOAP_1_2_PROTOCOL);
            SOAPMessage response = factory.createMessage();
            SOAPBody body = response.getSOAPBody();
            SOAPFault fault = body.addFault();
            fault.setFaultCode(SOAPConstants.SOAP_RECEIVER_FAULT);
            // Do not expose internal details in fault messages
            fault.setFaultString(sanitizeOutput(faultMessage));
            response.saveChanges();
            return response;
        } catch (SOAPException e) {
            LOGGER.log(Level.SEVERE, "Error creating SOAP fault response", e);
            return null;
        }
    }

    // --- Utility methods ---

    private Node getFirstElementChild(Node parent) {
        NodeList children = parent.getChildNodes();
        for (int i = 0; i < children.getLength(); i++) {
            if (children.item(i).getNodeType() == Node.ELEMENT_NODE) {
                return children.item(i);
            }
        }
        return null;
    }

    private NodeList getDirectChildElements(Element parent, String localName) {
        List<Element> matchingElements = new ArrayList<>();
        NodeList children = parent.getChildNodes();
        for (int i = 0; i < children.getLength(); i++) {
            Node child = children.item(i);
            if (child.getNodeType() == Node.ELEMENT_NODE && localName.equals(child.getLocalName())) {
                matchingElements.add((Element) child);
            }
        }
        // Return as a simple NodeList wrapper
        return new SimpleNodeList(matchingElements);
    }

    private String getElementTextContent(Element parent, String childLocalName) {
        NodeList children = parent.getChildNodes();
        for (int i = 0; i < children.getLength(); i++) {
            Node child = children.item(i);
            if (child.getNodeType() == Node.ELEMENT_NODE && childLocalName.equals(child.getLocalName())) {
                String text = child.getTextContent();
                return text != null ? text.trim() : null;
            }
        }
        return null;
    }

    /**
     * Sanitizes input to prevent injection attacks.
     */
    private String sanitizeInput(String input) {
        if (input == null) {
            return null;
        }
        // Remove control characters except tab, newline, carriage return
        return input.replaceAll("[\\x00-\\x08\\x0B\\x0C\\x0E-\\x1F\\x7F]", "").trim();
    }

    /**
     * Sanitizes output for XML responses.
     */
    private String sanitizeOutput(String output) {
        if (output == null) {
            return "";
        }
        return output
                .replace("&", "&amp;")
                .replace("<", "&lt;")
                .replace(">", "&gt;")
                .replace("\"", "&quot;")
                .replace("'", "&apos;")
                .replaceAll("[\\x00-\\x08\\x0B\\x0C\\x0E-\\x1F\\x7F]", "");
    }

    /**
     * Sanitizes messages for log output to prevent log injection.
     */
    private String sanitizeLogMessage(String message) {
        if (message == null) {
            return "null";
        }
        return message.replaceAll("[\\r\\n\\t]", "_").replaceAll("[^\\x20-\\x7E]", "?");
    }

    /**
     * Validates that an identifier contains only safe characters.
     */
    private boolean isValidIdentifier(String id) {
        if (id == null || id.isEmpty() || id.length() > 255) {
            return false;
        }
        return id.matches("^[a-zA-Z0-9_\\-.:]+$");
    }

    /**
     * Validates batch ID format.
     */
    private boolean isValidBatchId(String batchId) {
        if (batchId == null || batchId.isEmpty() || batchId.length() > 100) {
            return false;
        }
        return batchId.matches("^[a-zA-Z0-9_\\-]+$");
    }

