    /**
     * InputStream wrapper that limits the number of bytes read.
     */
    private static class LimitedInputStream extends FilterInputStream {
        private long bytesRead = 0;
        private final long maxBytes;

        public LimitedInputStream(InputStream in, long maxBytes) {
            super(in);
            this.maxBytes = maxBytes;
        }

        @Override
        public int read() throws IOException {
            if (bytesRead >= maxBytes) {
                throw new PayloadTooLargeException("Input exceeds maximum allowed size of " + maxBytes + " bytes.");
            }
            int result = super.read();
            if (result != -1) {
                bytesRead++;
            }
            return result;
        }

        @Override
        public int read(byte[] b, int off, int len) throws IOException {
            if (bytesRead >= maxBytes) {
                throw new PayloadTooLargeException("Input exceeds maximum allowed size of " + maxBytes + " bytes.");
            }
            long remaining = maxBytes - bytesRead;
            int safeLen = (int) Math.min(len, remaining);
            int result = super.read(b, off, safeLen);
            if (result > 0) {
                bytesRead += result;
            }
            return result;
        }
    }

    /**
     * Secure SAX error handler that doesn't expose internal details.
     */
    private static class SecureErrorHandler implements org.xml.sax.ErrorHandler {
        private static final Logger LOGGER = Logger.getLogger(SecureErrorHandler.class.getName());

        @Override
        public void warning(org.xml.sax.SAXParseException exception) throws SAXException {
            LOGGER.log(Level.WARNING, "XML parsing warning at line " + exception.getLineNumber(), exception);
        }

        @Override
        public void error(org.xml.sax.SAXParseException exception) throws SAXException {
            LOGGER.log(Level.SEVERE, "XML parsing error at line " + exception.getLineNumber(), exception);
            throw new SAXException("XML parsing error.");
        }

        @Override
        public void fatalError(org.xml.sax.SAXParseException exception) throws SAXException {
            LOGGER.log(Level.SEVERE, "Fatal XML parsing error at line " + exception.getLineNumber(), exception);
            throw new SAXException("Fatal XML parsing error.");
        }
    }

    /**
     * Simple NodeList implementation for filtered child elements.
     */
    private static class SimpleNodeList implements NodeList {
        private final List<Element> elements;

        public SimpleNodeList(List<Element> elements) {
            this.elements = elements;
        }

        @Override
        public Node item(int index) {
            return elements.get(index);
        }

        @Override
        public int getLength() {
            return elements.size();
        }
    }

